-- ============================================================
-- Этап 8 «Фасад» (exterior) проекта Homesteader's Cabin —
-- эталонный контент из ЭТАП8_Фасад.md. Наружная отделка:
-- утепление 150 мм + ветрозащита + вентзазор (обязательно
-- для РФ), обшивка (планкен/сайдинг/гонт), покраска.
-- Скрипт покупки утеплителя и фасада — в hint шага 3.
-- Идемпотентно: пересоздаёт только шаги этапа exterior (id ...318).
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000318') then
    return;
  end if;

  update stages set intro = '🟣 Фиолетовый этап. Коробка стоит, окна вставлены — теперь «одеваем» дом снаружи: утепляем, защищаем от ветра и влаги, обшиваем красивым фасадом и красим. После этого этапа дом снаружи будет полностью готов — тот самый вид, что на картинке.

Это два дела в одном: защита (утепление + ветрозащита, чтоб было тепло и стены не мокли) и красота (сайдинг/планкен нужного цвета — лицо дома). Для нашего климата утепление снаружи обязательно — это то, что отличает тёплый дом от холодной дачи.

Займёт около 4 дней. Работа не тяжёлая, но кропотливая — много однообразной обшивки. Зато результат виден сразу: с каждой доской дом становится наряднее. Когда закончишь — отойди и полюбуйся: снаружи дом готов.'
  where id = 'de300000-0000-4000-8000-000000000318';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000318';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    self_check, hint, common_mistake, helpers_needed) values
  ('de300000-0000-4000-8000-000000000491',
   'de300000-0000-4000-8000-000000000318', 1,
   'Утепляем стены снаружи и ставим ветрозащиту',
   'Между стойками стен (или поверх) укладываем утеплитель, закрываем ветро-влагозащитной плёнкой. Без этого дом холодный, а стены мокнут от конденсата. Для России — основа тёплого дома.',
   'Купи заранее (из сметы): утеплитель (минвата) ~150 мм — по площади стен (в стойки 50×150 как раз входит); ветро-влагозащитная мембрана (плёнка); бруски для контробрешётки (вентзазор); крепёж.',
   '["Уложи утеплитель между стойками стен изнутри или снаружи (по проекту), плотно, без щелей. Толщина ~150 мм (в стойку 50×150).","Снаружи закрой стены ветро-влагозащитной мембраной — она не пускает ветер и воду снаружи, но выпускает пар изнутри. Крепи степлером, стыки внахлёст и проклей.","Поверх мембраны прибей бруски контробрешётки (вертикально) — они создают вентиляционный зазор между мембраной и фасадом. Воздух гуляет, стена сохнет."]',
   '{"степлер","нож"}',
   '["Утеплитель уложен плотно, без щелей (~150 мм)","Ветрозащитная мембрана закрывает стены, стыки внахлёст","Прибита контробрешётка (вентзазор 2-3 см)"]',
   'Вентзазор (те самые бруски под фасадом) — важнейшая штука. Без него влага не уходит, фасад и утеплитель сыреют. 2-3 см зазора спасают стену от гнили. Не пропускай.',
   'Прибить фасад прямо на утеплитель без зазора и мембраны. Стена не дышит, копится конденсат, через пару лет — плесень и гниль. Мембрана + зазор обязательны.',
   0),
  ('de300000-0000-4000-8000-000000000492',
   'de300000-0000-4000-8000-000000000318', 2,
   'Обшиваем фасад (сайдинг / планкен / гонт)',
   'Поверх вентзазора крепим фасадный материал — это финальная «одёжка» дома, его лицо. На рендерах — кедровый гонт (чешуйки) тёплого цвета.',
   'Купи заранее: фасадный материал — планкен (деревянные рейки) / сайдинг / гонт — по площади стен; крепёж (оцинкованный, не ржавеет); стартовые и угловые планки.',
   '["Начинай снизу, со стартовой планки — она задаёт ровную нижнюю линию.","Крепи фасадные доски/панели снизу вверх, внахлёст (чтоб вода стекала поверху) или встык с зазором — по типу материала.","Проверяй уровнем каждые несколько рядов — чтоб не «поехало» вбок.","Обходи окна и двери аккуратно — по периметру ставь наличники/планки.","На углах — угловые планки, закрывают торцы."]',
   '{"уровень","пила","шуруповёрт или молоток"}',
   '["Стартовая планка ровная (по уровню)","Фасад обшит снизу вверх, ровно","Окна/двери обрамлены наличниками","Углы закрыты планками, крепёж оцинкованный"]',
   'Выбор фасада — это про стиль и бюджет. Планкен (деревянные рейки) — модно, скандинавский вид, но дороже и требует ухода. Сайдинг — дешевле и без ухода, но менее «натуральный». Гонт (как на картинке) — красиво, но трудоёмко. Выбирай под свой вкус и кошелёк в конфигураторе.',
   'Крепить фасад обычным (чёрным) крепежом — заржавеет, пойдут потёки. Только оцинкованный/нержавеющий крепёж снаружи.',
   0),
  ('de300000-0000-4000-8000-000000000493',
   'de300000-0000-4000-8000-000000000318', 3,
   'Красим и защищаем фасад',
   'Дерево снаружи надо защитить от солнца, дождя, грибка — покрываем защитным составом и краской нужного цвета. Это и защита, и финальный цвет дома.',
   'Купи заранее: антисептик-грунт для дерева (защита от гнили/грибка); фасадная краска или масло нужного цвета.',
   '["Сначала покрой фасад антисептиком-грунтом (если дерево не обработано на заводе) — защита от гнили и жучка.","Нанеси фасадную краску или масло в 2 слоя, давая просохнуть между слоями.","Тёмные акценты (наличники, углы, подкосы) — контрастным цветом, как на рендерах (тёмное к светлому — стильно).","Не крась в сырую погоду и под палящим солнцем — краска ляжет плохо."]',
   '{"кисти","валик","лестница"}',
   '["Фасад обработан антисептиком-грунтом","Краска/масло в 2 слоя, просохло","Акценты выделены контрастным цветом","Красил в сухую нежаркую погоду"]',
   'Цвет фасада — это характер дома. На картинке тёплый коричневый + тёмные акценты = уютно и стильно. Но можешь выбрать своё: тёмно-серый/чёрный (модный барнхаус), натуральное дерево под лаком. Это твой дом — твой цвет.

СКРИПТ — покупка утеплителя и фасада. Утеплитель и фасад — большие площади, большие деньги; экономия на утеплителе = холодный дом навсегда. Про утеплитель: «Плотность для стен?» — для стен каркасника плита плотностью ~35-50 кг/м³ (не «мягкий рулон», он осядет), спрашивай плитный; «Не боится влаги? Есть ветрозащита в комплекте?» — мембрану бери отдельно, качественную; считай по площади стен + 10% на подрезку. Про фасад: планкен/имитация бруса — «сухой, строганый, сорт АВ?» — для фасада на виду только качественный; крепёж — «оцинкованный или нержавеющий?» — обычный заржавеет; посчитай площадь с запасом 10-15%. Красные флаги: мягкий рулонный утеплитель для стен (осядет, появятся холодные зоны сверху), фасадная доска сырая (растрескается), чёрный крепёж для наружки. Ориентир: утепление + фасад — крупная статья; на утеплителе не экономь (это тепло на весь срок дома), фасад выбирай по бюджету в конфигураторе.',
   'Покрасить необработанное дерево сразу краской без антисептика. Под краской заведётся грибок, дерево сгниёт изнутри. Сначала защита, потом цвет.',
   0);
end
$do$;
